import pytest
import requests

BASE_URL = "<base_url_fixture>"


@pytest.fixture
def admin_headers():
    return <get_auth_headers>(role="admin")


@pytest.fixture
def nurse_headers():
    return <get_auth_headers>(role="nurse")


@pytest.fixture
def existing_patient(admin_headers):
    payload = {"resourceType": "Patient", "active": True, "name": [{"family": "TestNEG"}]}
    r = requests.post(f"{BASE_URL}/Patient", json=payload, headers=admin_headers)
    assert r.status_code in (200, 201)
    pid = r.json()["id"]
    yield pid
    requests.delete(f"{BASE_URL}/Patient/{pid}", headers=admin_headers)


def test_non_admin_delete_patient_returns_403(nurse_headers, existing_patient, admin_headers):
    pid = existing_patient
    del_r = requests.delete(f"{BASE_URL}/Patient/{pid}", headers=nurse_headers)
    assert del_r.status_code == 403

    get_r = requests.get(f"{BASE_URL}/Patient/{pid}", headers=admin_headers)
    assert get_r.status_code == 200
    tags = [t.get("code") for t in get_r.json().get("meta", {}).get("tag", [])]
    assert "deleted" not in tags

import pytest
import requests

BASE_URL = "<base_url_fixture>"


@pytest.fixture
def admin_headers():
    return <get_auth_headers>(role="admin")


@pytest.fixture
def deletable_patient(admin_headers):
    payload = {"resourceType": "Patient", "active": True, "name": [{"family": "TestSTC"}]}
    r = requests.post(f"{BASE_URL}/Patient", json=payload, headers=admin_headers)
    assert r.status_code in (200, 201)
    pid = r.json()["id"]
    yield pid
    requests.delete(f"{BASE_URL}/Patient/{pid}", headers=admin_headers)


def test_double_delete_already_deleted_patient(admin_headers, deletable_patient):
    pid = deletable_patient
    first = requests.delete(f"{BASE_URL}/Patient/{pid}", headers=admin_headers)
    assert first.status_code in (200, 204)

    second = requests.delete(f"{BASE_URL}/Patient/{pid}", headers=admin_headers)
    assert second.status_code in (200, 204, 410), (
        f"Unexpected status on double-delete: {second.status_code}"
    )
    assert second.status_code != 500

    hist_r = requests.get(f"{BASE_URL}/Patient/{pid}/_history", headers=admin_headers)
    assert hist_r.status_code == 200
    assert len(hist_r.json().get("entry", [])) >= 1

import uuid
