import requests
import pytest

BASE_URL = "<base_url_fixture>"
MIN_ID = "a"


@pytest.fixture
def admin_headers():
    return <get_auth_headers>(role="admin")


def test_delete_patient_with_minimum_length_id(admin_headers):
    # Attempt to PUT/create with explicit minimal ID
    payload = {"resourceType": "Patient", "id": MIN_ID, "active": True}
    put_r = requests.put(f"{BASE_URL}/Patient/{MIN_ID}", json=payload, headers=admin_headers)

    if put_r.status_code in (200, 201):
        del_r = requests.delete(f"{BASE_URL}/Patient/{MIN_ID}", headers=admin_headers)
        assert del_r.status_code in (200, 204)
        hist_r = requests.get(f"{BASE_URL}/Patient/{MIN_ID}/_history", headers=admin_headers)
        assert hist_r.status_code == 200
        assert len(hist_r.json().get("entry", [])) >= 1
    else:
        # Server does not allow explicit minimal IDs – confirm DELETE gives 404 not 5xx
        del_r = requests.delete(f"{BASE_URL}/Patient/{MIN_ID}", headers=admin_headers)
        assert del_r.status_code in (404, 410)
        assert del_r.status_code < 500
